import React, { useState } from 'react'

function App() {
 const [car,setcar]=useState({
  name:"bmw",
  number:"123",
  color:"red"

 })

 const setcolor=()=>{
  setcar((prev)=>{
     return {...prev,color:"red"}
  })
 }
 return (
 <div>
  <h1>{car.name}- {car.color}</h1>
  <button onClick={setcolor}> Click</button>
 </div>
  )
}

export default App
